patch:
--- a/priority_encoder_64bit.v
+++ b/priority_encoder_64bit.v
@@ -6,7 +6,7 @@
     output reg [5:0] priority
   );

-  always @(data_in)
+  always @(*)
   begin
     priority = 6'b0;
     if (data_in[63])

before_code:
module priority_encoder_64bit (
  input [63:0] data_in,
  output reg [5:0] priority
);

  always @(data_in)
  begin
    priority = 6'b0;
    if (data_in[63])
      priority = 6'd63;
    else if (data_in[62])
      priority = 6'd62;
    else if (data_in[1])
      priority = 6'd1;
    else if (data_in[0])
      priority = 6'd0;
  end

endmodule

after_code:
module priority_encoder_64bit (
  input [63:0] data_in,
  output reg [5:0] priority
);

  always @(*)
  begin
    priority = 6'b0;
    if (data_in[63])
      priority = 6'd63;
    else if (data_in[62])
      priority = 6'd62;
    else if (data_in[1])
      priority = 6'd1;
    else if (data_in[0])
      priority = 6'd0;
  end

endmodule
